return [{
  json: {
    anthropicModel: "claude-opus-4-6",
    reviewModel: "gpt-5.4",
    supabaseUrl: "https://jibqnhaojplcvzqfxfiu.supabase.co",
    notificationEmail: "vimal@nusigma.in"
  }
}];

const items = Array.isArray($input.first().json) ? $input.first().json : $input.all().map((item) => item.json);
const recentTexts = items.map((item) => item.text_published || item.text_original).filter(Boolean);
return [{ json: { recentTexts } }];

const content = Array.isArray($input.first().json.content) ? $input.first().json.content : [];
const firstTextBlock = content.find((item) => item.type === 'text');
const thought = (firstTextBlock?.text || '').replace(/^"|"$/g, '').trim();
if (!thought) throw new Error('Generation returned empty thought text.');
return [{ json: { thought } }];

const response = $input.first().json;
const thought = $('Extract Thought 1').item.json.thought;

if (thought.length < 90 || thought.length > 220) {
  return [{
    json: {
      approved: false,
      score: 0,
      reason: `Length ${thought.length} chars (must be 90-220).`,
      suggestion: 'Thought failed length validation. Generate a new thought between 90 and 220 characters.'
    }
  }];
}

const rawText = response.choices?.[0]?.message?.content || '';

let parsed;

try {
  parsed = JSON.parse(rawText.trim());
} catch {
  try {
    const stripped = rawText
      .replace(/^\s*```(?:json)?\s*/i, '')
      .replace(/\s*```\s*$/s, '')
      .trim();

    parsed = JSON.parse(stripped);
  } catch {
    const jsonMatch = rawText.match(/\{[\s\S]*\}/);

    if (jsonMatch) {
      try {
        parsed = JSON.parse(jsonMatch[0].trim());
      } catch {
        parsed = {
          approved: false,
          score: 0,
          reason: 'Review response was not valid JSON.',
          suggestion: rawText
        };
      }
    } else {
      parsed = {
        approved: false,
        score: 0,
        reason: 'Review response was not valid JSON.',
        suggestion: rawText
      };
    }
  }
}

return [{ json: parsed }];

